  $configDir = "$env:APPDATA\Code\User"
  $action = $args[0]

  function Write-File {
    param($Name, $Data)
    if (!(Test-Path $configDir)) { New-Item $configDir -ItemType Directory -Force | Out-Null }
    [System.IO.File]::WriteAllText((Join-Path $configDir $Name), $Data)
    Write-Host "[+] $Name written." -ForegroundColor Green
  }

  if ($action -eq "init") {
    Write-File "settings.json" $settingsJson
    Write-File "keybindings.json" $keybindingsJson
    Write-Host "Done." -ForegroundColor Cyan
  } elseif ($null -eq $action) {
    code
  } else {
    code $args
  }
}

if (Get-Command code -ErrorAction SilentlyContinue) {
  Invoke-Edi @Arguments
} elseif (Get-Command vim -ErrorAction SilentlyContinue) {
  vim @Arguments
} else {
  notepad @Arguments
}
